                            firebase.myAppCheck[e.sdkName] = firebase.appcheck.initializeAppCheck(firebase.myApp[e.sdkName], {
                                provider: new firebase.appcheck[providerName](e.recaptchatoken),
                                isTokenAutoRefreshEnabled: e.autoRefCapToken
                            });
